import React, { useState, useEffect } from 'react';
import { Platform, Alert, NativeModules } from 'react-native';
import { RNIap, purchaseUpdatedListener, purchaseErrorListener, requestPurchase, getProducts, getSubscriptions, finishTransaction } from 'react-native-iap';
import { Stripe } from 'stripe-react-native';

const PaymentModule = () => {
  const [products, setProducts] = useState([]);
  const [subscriptions, setSubscriptions] = useState([]);
  const [isInitialized, setIsInitialized] = useState(false);
  const [stripe, setStripe] = useState(null);

  useEffect(() => {
    initializePayment();
    return () => {
      if (purchaseUpdatedListener) purchaseUpdatedListener.remove();
      if (purchaseErrorListener) purchaseErrorListener.remove();
    };
  }, []);

  const initializePayment = async () => {
    try {
      if (Platform.OS === 'ios') {
        await RNIap.initConnection();
      }
      
      const productsData = await getProducts(['product_id_1', 'product_id_2']);
      const subsData = await getSubscriptions(['subscription_id_1']);
      
      setProducts(productsData);
      setSubscriptions(subsData);
      setIsInitialized(true);
      
      const stripeInstance = new Stripe('pk_test_your_publishable_key');
      setStripe(stripeInstance);
    } catch (error) {
      console.error('Payment initialization failed:', error);
      Alert.alert('Error', 'Failed to initialize payment system');
    }
  };

  const processInAppPurchase = async (productId) => {
    try {
      const purchase = await requestPurchase(productId, false);
      return purchase;
    } catch (error) {
      console.error('Purchase failed:', error);
      Alert.alert('Purchase Failed', error.message);
      throw error;
    }
  };

  const processDigitalWallet = async (amount, currency = 'usd') => {
    try {
      if (!stripe) {
        throw new Error('Stripe not initialized');
      }
      
      const { clientSecret } = await fetch('/api/payment-intent', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ amount, currency })
      }).then(res => res.json());

      const result = await stripe.confirmPayment(clientSecret, {
        paymentMethodType: 'card',
      });

      if (result.error) {
        throw new Error(result.error.message);
      }
      
      return result;
    } catch (error) {
      console.error('Digital wallet payment failed:', error);
      Alert.alert('Payment Failed', error.message);
      throw error;
    }
  };

  const handlePurchaseUpdate = (purchase) => {
    finishTransaction(purchase.purchaseToken, false);
  };

  const handlePurchaseError = (error) => {
    console.error('Purchase error:', error);
  };

  const listenForPurchases = () => {
    const purchaseUpdateSubscription = purchaseUpdatedListener(handlePurchaseUpdate);
    const purchaseErrorSubscription = purchaseErrorListener(handlePurchaseError);
    
    return () => {
      purchaseUpdateSubscription.remove();
      purchaseErrorSubscription.remove();
    };
  };

  const validatePaymentData = (data) => {
    const regex = {
      email: /^[^\s@]+@[^\s@]+\.[^\s@]+$/,
      phone: /^\+?[1-9]\d{1,14}$/,
      cardNumber: /^\d{13,19}$/
    };
    
    if (data.email && !regex.email.test(data.email)) {
      throw new Error('Invalid email format');
    }
    
    if (data.phone && !regex.phone.test(data.phone)) {
      throw new Error('Invalid phone number format');
    }
    
    if (data.cardNumber && !regex.cardNumber.test(data.cardNumber)) {
      throw new Error('Invalid card number');
    }
  };

  return {
    products,
    subscriptions,
    isInitialized,
    processInAppPurchase,
    processDigitalWallet,
    listenForPurchases,
    validatePaymentData
  };
};

export default PaymentModule;